#include <fstream>
#include <string>
#include <iostream>
#include <cstdio> // For std::remove

class Logger {
public:
    Logger(const std::string& filename) : logFilename(filename) {
        outFile.open(logFilename, std::ios::app);
        if (!outFile.is_open()) {
            std::cerr << "Error: Could not open log file " << logFilename << std::endl;
        }
    }

    ~Logger() {
        if (outFile.is_open()) {
            outFile.close();
        }
    }

    void logMessage(const std::string& message) {
        if (outFile.is_open()) {
            outFile << message << std::endl;
        } else {
            std::cerr << "Error: Log file is not open. Message not logged." << std::endl;
        }
    }

private:
    std::ofstream outFile;
    std::string logFilename;
};

int main() {
    std::string test_file = "test_log_2831.txt";
    std::remove(test_file.c_str());

    Logger logger(test_file);
    logger.logMessage("Hello World");
    logger.logMessage("Another message");

    std::ifstream inFile(test_file);
    if (inFile.is_open()) {
        std::string line;
        while (std::getline(inFile, line)) {
            std::cout << line << std::endl;
        }
        inFile.close();
    } else {
        std::cout << "Log file could not be opened for reading." << std::endl;
    }
    std::remove(test_file.c_str());
    return 0;
}
